{
  "summary": "A dual-layered horizontal energy beam effect featuring a high-intensity white core, a golden outer glow, and floating square-shaped 'shimmer' particles that drift vertically while fading.",
  "duration_ms": 600,
  "palette": [
    "#FFFFFF",
    "#FFF59D",
    "#FFD54F",
    "#FB8C00"
  ],
  "particle_config": {
    "count": 12,
    "shape": "square",
    "velocity_y": {
      "min": -40,
      "max": 40
    },
    "velocity_x": {
      "min": -10,
      "max": 10
    },
    "scale": {
      "start": 0.4,
      "end": 0
    },
    "alpha": {
      "start": 1,
      "end": 0
    },
    "rotation": {
      "min": 0,
      "max": 360
    },
    "blend_mode": "ADD"
  },
  "typescript": "export function createHorizontalClear(scene: Phaser.Scene, x: number, y: number, width: number) {
  const container = scene.add.container(x, y);
  const duration = 600;

  // 1. Create Procedural Glow Beam
  const beamGlow = scene.add.graphics();
  beamGlow.fillStyle(0xFFD54F, 0.6);
  beamGlow.fillRect(-width / 2, -15, width, 30);
  beamGlow.fillStyle(0xFFFFFF, 0.9);
  beamGlow.fillRect(-width / 2, -4, width, 8);
  container.add(beamGlow);

  // 2. Particle Texture Generation
  const rectKey = 'vfx_square';
  if (!scene.textures.exists(rectKey)) {
    const graphics = scene.make.graphics({ x: 0, y: 0, add: false });
    graphics.fillStyle(0xffffff).fillRect(0, 0, 16, 16);
    graphics.generateTexture(rectKey, 16, 16);
  }

  // 3. Particle Emitter
  const emitter = scene.add.particles(0, 0, rectKey, {
    lifespan: duration,
    speedY: { min: -50, max: 50 },
    speedX: { min: -20, max: 20 },
    scale: { start: 0.5, end: 0 },
    alpha: { start: 1, end: 0 },
    rotate: { min: 0, max: 180 },
    blendMode: 'ADD',
    tint: [0xFFFFFF, 0xFFF59D, 0xFFD54F],
    frequency: -1,
    emitZone: { type: 'random', source: new Phaser.Geom.Rectangle(-width / 2, -10, width, 20) }
  });
  container.add(emitter);
  emitter.explode(15);

  // 4. Animation Sequence
  scene.tweens.add({
    targets: beamGlow,
    scaleY: { from: 0, to: 1.5 },
    alpha: { from: 1, to: 0 },
    duration: duration,
    ease: 'Cubic.easeOut',
    onComplete: () => container.destroy()
  });
}"
}
}
